def merge_within(pairs):
    if not pairs:
        return []

    merged = sorted(pairs)
    result = [merged[0]]

    for current in merged[1:]:
        last_merged = result[-1]

        if current[0] <= last_merged[1]:
            result[-1] = [last_merged[0], max(last_merged[1], current[1])]
        else:
            result.append(current)

    return result
